import java.util.ArrayList;

public class Bookstore
{
	private final ArrayList<String> books;

	public Bookstore()
	{
		books = new ArrayList<>();

		books.add("Learning Java");
		books.add("Java 101");

		for (String book : books)
		{
			System.out.println(book.toUpperCase());
		}
	}
}

public class Movie
{
	private final String title;

	public Movie(String title)
	{
		if (title == null || title.isEmpty() || title.length() < 6 || title.toLowerCase().contains("bcit"))
		{
			throw new IllegalArgumentException("WRONG");
		}
		this.title = title;
	}

	public String getTitle()
	{
		return title;
	}
}

public class Main
{
	public static void main(String[] args)
	{
		Movie movie = new Movie("Inception");
		System.out.println(movie.getTitle().toUpperCase());
	}
}

public class BadName extends Exception
{
	public BadName (String message)
	{
		super(message);
	}
}

public class Dog
{
	private final String name;

	public Dog (String name)
		throws BadName
	{
		if (name == null)
		{
			throw new BadName(\"Name cannot be null\");
		}
		this.name = name;
	}

	public String getName()
	{
		return name;
	}
}
